sql:
SELECT MAX(duration_minutes) AS longest_trip_duration
FROM trips
WHERE usertype = 'member' AND user_id = 1;

SELECT AVG(duration_minutes) AS average_sunny_trip_duration
FROM trips
WHERE usertype = 'casual' AND weather_conditions = 'Sunny';

